// app/blog/[id]/page.js
export default function BlogPost({ params }) {
  return <h1>Blog ID: {params.id}</h1>;
}

console.log('Tək segment dinamik route yaradıldı');

// app/docs/[...slug]/page.js
export default function DocsPage({ params }) {
  return (
    <div>
      <h1>Docs Yol: {params.slug?.join('/') || 'Ana'}</h1>
    </div>
  );
}

console.log('Catch-all route yaradıldı');

// app/shop/[[...slug]]/page.js
export default function ShopPage({ params }) {
  const slug = params.slug || [];
  return <h1>Shop Yol: {slug.join('/') || 'Ana'}</h1>;
}

console.log('Optional catch-all route yaradıldı');

// pages/blog/[id].js
function BlogPost({ params }) {
  return <h1>Blog ID: {params.id}</h1>;
}

export function getServerSideProps({ params }) {
  return { props: { params } };
}

export default BlogPost;

console.log('Pages Router dinamik route');

